import React from 'react';
import { Card, CardContent, Box, Typography, Stack, LinearProgress } from '@mui/material';
import response from './response.json';

interface SavingsGoalData {
  targetAmount: number;
  currentAmount: number;
  progressPercentage: number;
  projectedCompletionDate: string;
}

export default function Widget() {
  const savingsGoalData = response.data.savingsGoal as SavingsGoalData;
  const { targetAmount, currentAmount, progressPercentage, projectedCompletionDate } = savingsGoalData;
  const { primaryColor, accentColor } = response.meta;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 3 }}>
        <Stack spacing={2.5}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: primaryColor }}>
              Savings Goal
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#1F2937' }}>
              ${currentAmount.toLocaleString()}
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mt: 0.5 }}>
              of ${targetAmount.toLocaleString()} goal
            </Typography>
          </Box>

          <Box>
            <Stack direction="row" justifyContent="space-between" sx={{ mb: 0.5 }}>
              <Typography variant="caption" color="text.secondary">
                Progress
              </Typography>
              <Typography variant="caption" fontWeight={600} sx={{ color: primaryColor }}>
                {progressPercentage}%
              </Typography>
            </Stack>
            <LinearProgress
              variant="determinate"
              value={progressPercentage}
              sx={{
                height: 8,
                borderRadius: 4,
                bgcolor: `${primaryColor}20`, // Lighter shade of primary color
                '& .MuiLinearProgress-bar': {
                  bgcolor: primaryColor,
                  borderRadius: 4,
                }
              }}
            />
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary">
              Projected Completion Date
            </Typography>
            <Typography variant="body1" fontWeight={500} sx={{ color: accentColor }}>
              {projectedCompletionDate}
            </Typography>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
